import "fmt"

type MessageEvidence struct {
	ID            string
	Type          string
	SchemaVersion int
	BodyBytes     int
}

type DeliveryEvidence struct {
	Route            string
	Owner            string
	TerminalDecision string
	Attempt          int
}

